写一写
#include<bits/stdc++.h>
using namespace std;
string pre,mid;
struct node{
    char data;
    int left,right;
}BTree[30];
int p=0;//存储结点时，可用的数组下标
int getTree(int pl,int pr,int ml,int mr){
    if(ml>mr) return -1;//空子树返回-1
    int t=p++;//存储当前结点编号    
    BTree[t].data=pre[pl];//存储根结点
    //找出根结点在中序序列中的下标
    int i=ml;
    while(i<=mr&&pre[pl]!=mid[i]) i++;
    //左子树长度
    int len=i-ml;
//构建左右子树
    BTree[t].left=getTree(pl+1,pl+len,ml,i-1);
    BTree[t].right=getTree(pl+len+1,pr,i+1,mr);
    return t;//返回当前结点位置编号
}
int main(){
    cin>>pre>>mid;
    int n=pre.size();
    int root=getTree(0,n-1,0,n-1);
    cout<<"二叉树的结点数："<<p;
    return 0;
}
变量p保存的值，即为二叉树结点总数

解题步骤
1. 创建变量和结构体数组
string pre,mid;
struct node{
    char data;
    int left,right;
}BTree[30];
2. 编写后序遍历函数
void postOrder(int root){
    if(root>=0){
        postOrder(BTree[root].left);
        postOrder(BTree[root].right);
        cout<<BTree[root].data;
    }
}

解题步骤
3. 编写中序加先序构建二叉树函数
int p=0;//存储结点时，可用的数组下标
int getTree(int pl,int pr,int ml,int mr){
    if(ml>mr) return -1;
    //根据先序序列的第一个字符确定根结点
    int t=p++;
    BTree[t].data=pre[pl];
    //根据中序序列，找出根结点下标，计算出左子树的长度
    int i=ml;
    while(i<=mr&&pre[pl]!=mid[i]) i++;
    int len=i-ml;
    //构建左右子树
    BTree[t].left=getTree(pl+1,pl+len,ml,i-1);
    BTree[t].right=getTree(pl+len+1,pr,i+1,mr);
    return t;//返回当前结点编号
}

解题步骤
4. 构建二叉树，并输出后序遍历序列。
int main(){
    cin>>pre>>mid;
    int n=pre.size();
    int root=getTree(0,n-1,0,n-1);
    postOrder(root);
    return 0;
}
求序列的长度，先序中序序列长度一样

完整代码
#include<bits/stdc++.h>
using namespace std;
string pre,mid;
struct node{
    char data;
    int left,right;
}BTree[30];
int p=0;
int getTree(int pl,int pr,int ml,int mr){
    if(ml>mr) return -1;
    int t=p++;
    BTree[t].data=pre[pl];
    int i=ml;
    while(i<=mr&&pre[pl]!=mid[i]) i++;
    int len=i-ml;
