bool bfs(int x){
  vis[x]=1; q.push(x); a[x]=1;//起点x放病毒 
 
  while(!q.empty()){
    int f=q.front();//取队首
    for(int i=1;i<=n;i++){//遍历结点
      if(g[f][i]==1&&vis[i]==1){//相连已访问
        if(a[f]==a[i])//病毒状态相同
          return 0;//无法满足要求
      }else if(g[f][i]==1&&vis[i]==0){//相连未访问
        a[i]=1-a[f];//设置不同病毒状态

        vis[i]=1;
        q.push(i);
      }
    }
    q.pop();//出队
  }
  return 1;//满足条件
}
