#include<bits/stdc++.h>
using namespace std;
int n,m;
int g[1010][1010];//邻接矩阵
queue<int> q;//队列
int vis[1010];//标记结点访问
int a[1010];//标记病毒状态(0没放,1放)
int sum[2];//sum[0]没放的数量;sum[1]放的数量
bool bfs(int x){//从起点x开始广度遍历
    vis[x]=1;
    q.push(x);//起点入队
    a[x]=1;//起点放病毒
    sum[0]=0,sum[1]=1;//更新病毒数量
    while(!q.empty()){
        int f=q.front();//取队首
        for(int i=1;i<=n;i++){//遍历结点
if(g[f][i]==1&&vis[i]==1){//相连已访问
        if(a[f]==a[i])//病毒状态相同
          return 0;
      }else if(g[f][i]==1&&vis[i]==0){//相连未访问
        a[i]=1-a[f];//设置相反病毒状态
        sum[a[i]]++;//记录数量
        vis[i]=1;
        q.push(i);
      }
    }
    q.pop();//出队
  }
  return 1;//满足条件
}

