        g[v][u]=1;
    }
    int ans=0;//结果
    for(int i=1;i<=n;i++){
        if(vis[i]) continue;//跳过访问过遍历的结点
        if(bfs(i)==0){//图无法满足题意
            cout<<"Impossible";
            return 0;
        }else//图满足题意
            //累加每个子图的最少病毒数量
            ans+=min(sum[0],sum[1]);
    }
    cout<<ans;
    return 0;
}

